import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';
import { Vex } from 'vex-sdk';

const bedrock = new BedrockAgentRuntimeClient({ region: 'us-east-1' });
const vex = new Vex({ apiKey: 'your-vex-key' });

async function safeInvokeAgent(input: string, sessionId: string) {
  const command = new InvokeAgentCommand({
    agentId: 'YOUR_AGENT_ID',
    agentAliasId: 'YOUR_ALIAS_ID',
    sessionId,
    inputText: input
  });

  const response = await bedrock.send(command);
  const completion = response.completion;

  // Verify insurance compliance
  const result = await vex.verify('bedrock-insurance', {
    input,
    output: completion,
    sessionId,
    metadata: { agentId: 'YOUR_AGENT_ID' }
  }, {
    guards: [
      'insurance-pii-redaction',
      'no-protected-class-reference',
      'claims-explainability',
      'session-state-consistency'
    ]
  });

  return result.status === 'BLOCK' 
    ? 'Compliance violation detected. Escalating to human review.' 
    : completion;
}

