def validate_kb_retrieval(retrieved_docs, claim_context):
    vex_result = vex_client.verify(
        'insurance-kb-retrieval',
        {
            'claimContext': claim_context,
            'retrievedDocs': [doc['text'] for doc in retrieved_docs],
            'docCount': len(retrieved_docs)
        },
        guards=[
            'sufficient-coverage-docs',
            'relevant-exclusion-clauses',
            'no-missing-underwriting-guidelines'
        ]
    )

    if vex_result.status == 'BLOCK':
        return {
            'retrievalQuality': 'INSUFFICIENT',
            'requiredDocsMissing': vex_result.violations,
            'action': 'Escalate to underwriter'
        }

    return {'retrievalQuality': 'SUFFICIENT', 'proceed': True}
